import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { listenAuction, startAuction, closeAuction, listenPlayers, addPlayer } from '../firebase/services';
import toast from 'react-hot-toast';

export default function AdminDashboard() {
  const { logout } = useAuth();
  const [auction, setAuction] = useState(null);
  const [players, setPlayers] = useState([]);
  const [settings, setSettings] = useState({ monthlyAmount: 5000, totalPlayers: 10 });

  // New Player Form State
  const [newPlayer, setNewPlayer] = useState({ name: '', email: '', password: '' });
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const unsubs = [listenAuction(setAuction), listenPlayers(setPlayers)];
    return () => unsubs.forEach(u => u());
  }, []);

  const handleAddPlayer = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await addPlayer(newPlayer.email, newPlayer.password, newPlayer.name);
      toast.success("Player added successfully!");
      setNewPlayer({ name: '', email: '', password: '' });
    } catch (err) {
      toast.error(err.message);
    } finally { setLoading(false); }
  };

  return (
    <div className="page-wide">
      <div className="navbar">
        <div className="navbar-brand">👑 Admin Panel</div>
        <button className="btn btn-danger btn-sm" onClick={logout}>Logout</button>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1.5fr', gap: '20px' }}>
        {/* LEFT COLUMN: ADD PLAYER */}
        <div className="card">
          <h3 className="card-title">Add New Player</h3>
          <form onSubmit={handleAddPlayer} style={{ marginTop: '15px' }}>
            <div className="form-group">
              <label className="form-label">Full Name</label>
              <input type="text" className="form-input" required value={newPlayer.name}
                onChange={e => setNewPlayer({...newPlayer, name: e.target.value})} />
            </div>
            <div className="form-group">
              <label className="form-label">Email (Main Key)</label>
              <input type="email" className="form-input" required value={newPlayer.email}
                onChange={e => setNewPlayer({...newPlayer, email: e.target.value})} />
            </div>
            <div className="form-group">
              <label className="form-label">Initial Password</label>
              <input type="password" className="form-input" required value={newPlayer.password}
                onChange={e => setNewPlayer({...newPlayer, password: e.target.value})} />
            </div>
            <button className="btn btn-primary btn-full" disabled={loading}>
              {loading ? "Adding..." : "Add Player"}
            </button>
          </form>
        </div>

        {/* RIGHT COLUMN: LIVE AUCTION CONTROL */}
        <div>
          <div className="card" style={{ textAlign: 'center' }}>
            <h3 className="card-title">Auction Control</h3>
            {auction?.active ? (
              <div style={{ marginTop: '20px' }}>
                <div className="badge badge-green">LIVE</div>
                <h1 style={{ fontSize: '3rem', color: 'var(--gold)', margin: '10px 0' }}>
                  ₹{auction.currentBid?.toLocaleString('en-IN')}
                </h1>
                <p style={{ color: 'var(--text-muted)' }}>Highest Bidder: {auction.currentBidderName || "None"}</p>
                <button className="btn btn-danger btn-full" style={{ marginTop: '20px' }} onClick={() => closeAuction(auction)}>
                  Stop & Confirm Winner
                </button>
              </div>
            ) : (
              <button className="btn btn-primary btn-full" style={{ marginTop: '20px' }} onClick={() => startAuction(settings)}>
                Start Monthly Auction
              </button>
            )}
          </div>

          {/* RECENT BIDS PREVIEW FOR ADMIN */}
          {auction?.active && (
            <div className="card">
              <h4 className="card-title">Live Bid Feed</h4>
              {auction.bids?.slice(-3).reverse().map((bid, i) => (
                <div key={i} className="bid-item">
                  <span>{bid.playerName}</span>
                  <span style={{ color: 'var(--gold)' }}>₹{bid.amount}</span>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
